const crypto = require('crypto');

// 1. 获取 Webhook 传过来的加密字符串
const encryptStr = $input.first().json.body?.xml?.encrypt;

if (!encryptStr) {
  return [{ json: { error: "未在输入中找到加密的 encrypt 字段" } }];
}

// 2.  👇 【必填】将这里的字符串替换成你在企微后台生成的 EncodingAESKey
const encodingAESKey = '6N25bnbuG4r0AsrNup97QNj6lE2kPer3bycziA4eXih'; 

try {
  // 3. 企业微信官方解密算法
  const aesKey = Buffer.from(encodingAESKey + '=', 'base64');
  const iv = aesKey.subarray(0, 16);
  const encryptedData = Buffer.from(encryptStr, 'base64');

  const decipher = crypto.createDecipheriv('aes-256-cbc', aesKey, iv);
  decipher.setAutoPadding(false); 

  let decrypted = Buffer.concat([decipher.update(encryptedData), decipher.final()]);

  // 去除 PKCS#7 补位字符
  let pad = decrypted[decrypted.length - 1];
  if (pad < 1 || pad > 32) { pad = 0; }
  decrypted = decrypted.subarray(0, decrypted.length - pad);

  // 截取真实内容 (去掉前16字节随机数，和4字节长度)
  const contentStr = decrypted.subarray(16);
  const xmlLen = contentStr.readUInt32BE(0);

  // 这就是解密后的明文 XML 字符串！
  const finalXmlStr = contentStr.subarray(4, 4 + xmlLen).toString('utf8');

  // 4. 从明文 XML 中提取用户发来的真实文字和发送者ID
  // 企业微信解密后的明文通常长这样: <xml><Content><![CDATA[你好]]></Content><FromUserName>...</FromUserName>...</xml>
  const contentMatch = finalXmlStr.match(/<Content><!\[CDATA\[([\s\S]*?)\]\]><\/Content>/);
  const fromUserMatch = finalXmlStr.match(/<FromUserName><!\[CDATA\[(.*?)\]\]><\/FromUserName>/);

  const realchatInput = contentMatch ? contentMatch[1] : "未提取到文本/非文本消息";
  const sessionId = fromUserMatch ? fromUserMatch[1] : "未知发送者";

  // 5. 输出给下一个节点 (比如你的 AI 节点)
  return [{
    json: {
      success: true,
      chatInput: realchatInput,           // 用户发送的真实文字 ！！！
      sessionId: sessionId,         // 是谁发的
      rawDecryptedXML: finalXmlStr // 保留一份完整的明文以供调试查阅
    }
  }];

} catch (err) {
  return [{ json: { error: "解密失败，请检查 EncodingAESKey 是否正确", details: err.message } }];
}

const crypto = require('crypto');

// 👇 【必填】将这里的字符串替换成你在企微后台生成的 EncodingAESKey
const encodingAESKey = '6N25bnbuG4r0AsrNup97QNj6lE2kPer3bycziA4eXih';

// 1. 获取企微发来的参数，兼容不同的n8n版本
let echostr = $input.first().json.query.echostr;

if (!echostr) {
  return[{ json: { result: "没有收到echostr参数" } }];
}

// ⚠️ 极其关键的一步：修复 HTTP 传输中丢失的加号
echostr = echostr.replace(/ /g, '+');

try {
  // 2. 企微官方的 AES-256-CBC 解密过程
  const aesCipher = Buffer.from(echostr, 'base64');
  const aesKey = Buffer.from(encodingAESKey + '=', 'base64');
  const iv = aesKey.slice(0, 16);

  const decipher = crypto.createDecipheriv('aes-256-cbc', aesKey, iv);
  decipher.setAutoPadding(false); // 企微使用自定义补码

  let decrypted = Buffer.concat([decipher.update(aesCipher), decipher.final()]);

  // 3. 去除 PKCS#7 补码
  const pad = decrypted[decrypted.length - 1];
  decrypted = decrypted.slice(0, decrypted.length - pad);

  // 4. 解析出明文内容 (跳过前16位随机数，读取4位长度，截取正文)
  const contentLen = decrypted.readInt32BE(16);
  const content = decrypted.slice(20, 20 + contentLen).toString('utf8');

  // 5. 将解密后的纯文本传递给下一个节点
  return[{ json: { result: content } }];

} catch (error) {
  return[{ json: { result: "解密报错了: " + error.message } }];
}
